import EventEmitter from 'events';
import syslog from 'syslog-client';
import FormatHelper from './format-helper';

const syslogInfo = {
    port: 514,
    target: "127.0.0.1"
};


class SyslogBackend extends EventEmitter {  // gets original arguments
    constructor() {
        super();
        this.isWriting = false;
        this.writeQueue = [];
        this.client = undefined;
        this.enabled = false;
        this._test = []; // map of what "names" can go to syslog

        if(process.platform === 'linux' && process.arch === 'arm') {
            this.enabled = true;
        }
        else {
            this.enabled = false; // don't bother on anything other than our linux/arm environment
        }

        // if we are turning on syslogging and there isn't a client, then start the client
        if (this.enabled && !this.client) {
            let options = {
                port: syslogInfo.port,
                transport: syslog.Transport.Udp
            };
            this.client = syslog.createClient(syslogInfo.target, options);
            console.warn("Initializing a syslog client");

            this.client.on("error", function (error) {
                console.error(error);
                if (this.client) {
                    this.client.close();
                    this.client = undefined;
                }
            });
        }

        // if we are turning off syslogging and there currently is a client, then close the client
        if (!this.enabled && this.client) {
            this.client.close();
            this.client = undefined;
        }

    }

    // allow logging with this name to go to syslog
    allow(name) {
        if (name) {
            this._test.push(name);
        }
    }


    processNextInQueue() {
        if(this.writeQueue.length === 0) {
            this.isWriting = false;
            return;
        }

        const {name, level, args} = this.writeQueue.shift();
        let type = undefined;
        switch(level) {
            case 'log':
            case 'debug': {
                type = "Debug";
                break;
            }
            case 'warn': {
                type = "Warning";
                break;
            }
            case 'error': {
                type = "Error";
                break;
            }
            case 'info':
            default: {
                type = "Informational";
                break;
            }
        }


        let logOptions = {
            facility: syslog.Facility.Local0,
            severity: syslog.Severity[type]
        };

        let msg = FormatHelper(args);
        this.isWriting = true;
        this.client.log(`${name}: [${level}] ${msg}`, logOptions, (error) => {
            if (error) {
                console.error(error);
            }
            this.client.close();
            this.processNextInQueue();
        });
    }

    write(name, level, args) {  // EventEmitter
        // only write to syslog if it's enabled, has a client and the name exists in global mapping
        if (this.enabled && this.client && (this._test.indexOf(name) >= 0)) {
            this.writeQueue.push({name, level, args});
            if (!this.isWriting) {
                this.processNextInQueue();
            }
        }
    }
}




if(!GLOBAL.syslogBackend) {
    // Export the syslogBackend singleton
    GLOBAL.syslogBackend = new SyslogBackend();
}

export default GLOBAL.syslogBackend;
